-- =============================================================================
-- MERL Dashboard - Migration 0018: Indicator progress tracking
-- =============================================================================
-- Enriches each project indicator with numeric baseline / mid-term / end-of-
-- project target values, a unit, and a history of reported levels over time
-- (past -> current). This lets the dashboard measure progress toward the end-
-- of-project target and keep the trajectory even after the source document is
-- deleted (the data lives in merl.project_profiles, not in the uploaded file).
-- Updates the seeded VCAP2 indicators; new projects follow the same schema.
-- =============================================================================

BEGIN;

UPDATE merl.project_profiles
SET data = jsonb_set(data, '{indicators}', '[{"code": "Indicator 11", "description": "# direct project beneficiaries (individuals, gender-disaggregated)", "unit": "people", "baseline": "0", "midterm": "4,000", "end": "307,150 (entire population)", "status": "exceeded", "baseline_val": 0, "midterm_val": 4000, "end_val": 307150, "history": [{"period": "30 Jun 2025", "value": 4000, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 6684, "note": "3rd PIR (FY26): M 3,382 / F 3,302"}], "current": "3rd PIR (FY26): M 3,382 / F 3,302", "current_val": 6684, "progress_pct": 2}, {"code": "Core Indicator 1.1", "description": "Terrestrial protected areas newly created (ha)", "unit": "ha", "baseline": "0", "midterm": "1,000 ha", "end": "2,298 ha", "status": "exceeded", "baseline_val": 0, "midterm_val": 1000, "end_val": 2298, "history": [{"period": "30 Jun 2025", "value": 1000, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 3757, "note": "3rd PIR (FY26): 12,546 ha mapped"}], "current": "3rd PIR (FY26): 12,546 ha mapped", "current_val": 3757, "progress_pct": 163}, {"code": "Core Indicator 1.2", "description": "Terrestrial protected areas under improved management effectiveness (ha)", "unit": "ha", "baseline": "0", "midterm": "5,000 ha", "end": "11,215 ha", "status": "on_track", "baseline_val": 0, "midterm_val": 5000, "end_val": 11215, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 8099, "note": "3rd PIR (FY26): METTs for 3 CCAs; 13 METTs done"}], "current": "3rd PIR (FY26): METTs for 3 CCAs; 13 METTs done", "current_val": 8099, "progress_pct": 72}, {"code": "Indicator 10", "description": "# investments in climate-proofing of public conveyance, water provision and evacuation infrastructure", "unit": "investments", "baseline": "0", "midterm": "15", "end": "15", "status": "on_track", "baseline_val": 0, "midterm_val": 15, "end_val": 15, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 13, "note": "3rd PIR (FY26): 13 investments completed"}], "current": "3rd PIR (FY26): 13 investments completed", "current_val": 13, "progress_pct": 87}, {"code": "Indicator 12", "description": "% targeted V-CAP communities receiving timely, accurate early warnings of coastal hazards", "unit": "%", "baseline": "0", "midterm": "10%", "end": "100%", "status": "in_progress", "baseline_val": 0, "midterm_val": 10, "end_val": 100, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 0, "note": "3rd PIR (FY26): EW centre, TV weather station and AWS/river gauges under construction"}], "current": "3rd PIR (FY26): EW centre, TV weather station and AWS/river gauges under construction", "current_val": 0, "progress_pct": 0}, {"code": "Indicator 13", "description": "# climate change adaptation plans developed and integrated into Area Council Development Plans", "unit": "plans", "baseline": "0", "midterm": "10", "end": "20", "status": "on_track", "baseline_val": 0, "midterm_val": 10, "end_val": 20, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 3, "note": "3rd PIR (FY26): 3 CCAPs completed (South Epi)"}], "current": "3rd PIR (FY26): 3 CCAPs completed (South Epi)", "current_val": 3, "progress_pct": 15}, {"code": "Indicator 15", "description": "# people trained (gender-disaggregated)", "unit": "people", "baseline": "0", "midterm": "500 (F 250)", "end": "2,000 (F 1,000)", "status": "on_track", "baseline_val": 0, "midterm_val": 500, "end_val": 2000, "history": [{"period": "30 Jun 2025", "value": 250, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 627, "note": "3rd PIR (FY26): M 414 / F 213"}], "current": "3rd PIR (FY26): M 414 / F 213", "current_val": 627, "progress_pct": 31}]'::jsonb),
    updated_at = now()
WHERE code = 'VCAP2';

COMMIT;
